DESCRIPTION = '生命保険・医療保険・就業不能保険の必要額を無料診断。年齢・家族構成・年収・住宅ローンを入力するだけで過剰加入・不足を即チェック。節約できる保険料の目安も計算。'
JS_CODE = "let familyType = 'child1';\n\nconst FAMILY = {\n    single: { label: '独身', children: 0, hasSpouse: false, eduCost: 0, lifeExpense: 0.6 },\n    couple: { label: '夫婦のみ', children: 0, hasSpouse: true, eduCost: 0, lifeExpense: 0.7 },\n    child1: { label: '子1人', children: 1, hasSpouse: true, eduCost: 1000, lifeExpense: 0.7 },\n    child2: { label: '子2人', children: 2, hasSpouse: true, eduCost: 2000, lifeExpense: 0.7 },\n    child3: { label: '子3人', children: 3, hasSpouse: true, eduCost: 3000, lifeExpense: 0.7 },\n    parent: { label: '親扶養', children: 0, hasSpouse: false, eduCost: 0, lifeExpense: 0.65 },\n};\n\n// 遺族年金（月額概算・万円）\nconst SURVIVORS_PENSION = { employee: 12, part: 5, self: 7 };\n\nfunction selectFamily(type, el) {\n    familyType = type;\n    document.querySelectorAll('.fam-btn').forEach(b => b.classList.remove('selected'));\n    el.classList.add('selected');\n    document.getElementById('loan-wrap').style.display =\n        document.getElementById('housing').value === 'own' ? 'block' : 'none';\n}\n\nfunction updateIncome() {\n    const v = parseInt(document.getElementById('income').value);\n    document.getElementById('income-disp').textContent = '年収 ' + v + '万円';\n}\n\ndocument.getElementById('housing').addEventListener('change', function() {\n    document.getElementById('loan-wrap').style.display = this.value === 'own' ? 'block' : 'none';\n});\n\nfunction fmt(n) { return Math.round(n).toLocaleString(); }\nfunction fmtW(n) { return Math.round(n / 10000) * 10000 >= 1000000\n    ? (n / 10000).toFixed(0) + '万円'\n    : fmt(Math.round(n / 1000) * 1000) + '円'; }\nfunction fmtM(n) { return fmt(Math.round(n)) + '万円'; }\n\nfunction calcAndShow() {\n    const income = parseInt(document.getElementById('income').value);\n    const savings = parseInt(document.getElementById('savings').value) || 0;\n    const spouseIncome = parseInt(document.getElementById('spouse-income').value) || 0;\n    const employ = document.getElementById('employ').value;\n    const housing = document.getElementById('housing').value;\n    const loan = housing === 'own' ? (parseInt(document.getElementById('loan').value) || 0) : 0;\n    const age = parseInt(document.getElementById('age').value);\n    const gender = document.getElementById('gender').value;\n    const fam = FAMILY[familyType];\n\n    const curLife = parseInt(document.getElementById('cur-life').value) || 0;\n    const curMedical = parseInt(document.getElementById('cur-medical').value) || 0;\n    const curDisability = parseInt(document.getElementById('cur-disability').value) || 0;\n\n    // ===== 生命保険（死亡保障）必要額 =====\n    const yearsToRetire = Math.max(0, 65 - age);\n    const monthlyLivingCost = income * 0.7 / 12; // 現在の生活費×0.7\n    const survivorMonths = fam.children > 0 ? Math.max(20, fam.children * 22) * 12 : 20 * 12;\n    const livingCostNeed = monthlyLivingCost * survivorMonths / 10000;\n    const eduCost = fam.eduCost;\n    const funeralCost = 200; // 万円\n    const loanNeed = loan;\n    const monthlyPension = SURVIVORS_PENSION[employ]; // 万円/月\n    const pensionTotal = monthlyPension * survivorMonths / 10000;\n    const spouseEarnings = spouseIncome * Math.max(15, yearsToRetire) * 0.7;\n    const lifeNeed = Math.max(0, livingCostNeed + eduCost + funeralCost + loanNeed - pensionTotal - savings - spouseEarnings);\n\n    // ===== 医療保険必要額 =====\n    // 高額療養費後の自己負担上限（月）\n    const monthlyMedCap = income <= 370 ? 5.7 : income <= 770 ? 8.7 : income <= 1160 ? 17.5 : 25.4; // 万円\n    const avgHospitalDays = 15;\n    const bedFeePerDay = 0.8; // 差額ベッド代（万円/日）\n    const monthlyMedNeed = monthlyMedCap + bedFeePerDay * avgHospitalDays; // 月あたり\n    const medicalNeedMonthly = Math.round(monthlyMedNeed / avgHospitalDays * 10000 / 10000 * 10); // 日額概算\n    const medicalNeedDaily = Math.max(5000, Math.round(monthlyMedNeed * 10000 / avgHospitalDays / 1000) * 1000);\n\n    // ===== 就業不能保険必要額 =====\n    const monthlyIncome = income / 12;\n    const kotekiRate = employ === 'employee' ? 0.67 : employ === 'part' ? 0.3 : 0.1;\n    const kotekiMonthly = monthlyIncome * kotekiRate; // 傷病手当金・障害年"
